test("retryEnrichment only requeues records that are already failed", async () => {
  type RetryRecord = {
    enrichment: {
      status: "pending" | "ready" | "failed";
    };
  };

  const calls: string[] = [];
  const writer = {
    setEnrichmentPending: async (id: string): Promise<RetryRecord> => {
      calls.push(id);
      return {
        enrichment: {
          status: "pending" as const
        }
      };
    },
    setEnrichmentReady: async (): Promise<RetryRecord> => ({
      enrichment: {
        status: "ready" as const
      }
    }),
    setEnrichmentFailed: async (): Promise<RetryRecord> => ({
      enrichment: {
        status: "failed" as const
      }
    })
  };

  await withAiEnv(
    {
      LLM_BASE: "https://mina.example/v1",
      TOKEN: "token",
      MODEL: "model"
    },
    async () => {
      const readyRecord = {
        enrichment: {
          status: "ready" as const
        }
      };

      const readyResult = await retryEnrichment(writer, "note-3", readyRecord);
      assert.equal(readyResult, readyRecord);

      await retryEnrichment(writer, "note-4", {
        enrichment: {
          status: "failed" as const
        }
      });
    }
  );

  assert.deepEqual(calls, ["note-4"]);
});

import "server-only";

import { type MinaAiConfigStatus, getMinaAiConfigStatus } from "@/features/ai/config";
import { MinaAiClientError } from "@/features/ai/client";
import type { EnrichmentState } from "@/features/enrichment/types";

type EnrichmentStateWriter<TRecord> = {
  setEnrichmentPending(id: string): Promise<TRecord>;
  setEnrichmentReady(id: string): Promise<TRecord>;
  setEnrichmentFailed(id: string, error: string): Promise<TRecord>;
};

function getConfigurationFailureMessage(configStatus: MinaAiConfigStatus) {
  if (configStatus.state === "disabled") {
    return "AI enrichment is disabled until LLM_BASE, TOKEN, and MODEL are set. Save succeeded without generated metadata.";
  }

  if (configStatus.state === "invalid") {
    return `AI enrichment is not fully configured. Missing: ${configStatus.missing.join(", ")}. Save succeeded without generated metadata.`;
  }

  return "AI enrichment failed.";
}

export function normalizeEnrichmentFailure(error: unknown) {
  if (error instanceof MinaAiClientError) {
    return error.message;
  }

  if (error instanceof Error && error.message.trim()) {
    return error.message.trim().slice(0, 240);
  }

  return "AI enrichment failed.";
}

export async function requestEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string) {
  const configStatus = getMinaAiConfigStatus();

  if (configStatus.state === "configured") {
    return writer.setEnrichmentPending(id);
  }

  return writer.setEnrichmentFailed(id, getConfigurationFailureMessage(configStatus));
}

export async function retryEnrichment<TRecord extends { enrichment: Pick<EnrichmentState, "status"> }>(
  writer: EnrichmentStateWriter<TRecord>,
  id: string,
  record: TRecord
) {
  if (record.enrichment.status !== "failed") {
    return record;
  }

  return requestEnrichment(writer, id);
}

export async function completeEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string) {
  return writer.setEnrichmentReady(id);
}

export async function failEnrichment<TRecord>(writer: EnrichmentStateWriter<TRecord>, id: string, error: unknown) {
  return writer.setEnrichmentFailed(id, normalizeEnrichmentFailure(error));
}

export const ENRICHMENT_STATUSES = ["pending", "ready", "failed"] as const;

export type EnrichmentStatus = (typeof ENRICHMENT_STATUSES)[number];

export type EnrichmentState = {
  status: EnrichmentStatus;
  error: string | null;
  attempts: number;
  updatedAt: Date | null;
};

export type EnrichmentRecordFields = {
  enrichmentStatus: string;
  enrichmentError: string | null;
  enrichmentAttempts: number;
  enrichmentUpdatedAt: Date | null;
};

export function normalizeEnrichmentStatus(status: string): EnrichmentStatus {
  if (ENRICHMENT_STATUSES.includes(status as EnrichmentStatus)) {
    return status as EnrichmentStatus;
  }

  return "failed";
}

export function toEnrichmentState(record: EnrichmentRecordFields): EnrichmentState {
  return {
    status: normalizeEnrichmentStatus(record.enrichmentStatus),
    error: record.enrichmentError,
    attempts: record.enrichmentAttempts,
    updatedAt: record.enrichmentUpdatedAt
  };
}

export function getEnrichmentStatusLabel(status: EnrichmentStatus) {
  switch (status) {
    case "pending":
      return "AI pending";
    case "ready":
      return "AI ready";
    case "failed":
      return "AI failed";
  }
}

export function getEnrichmentAttemptLabel(attempts: number) {
  return `Attempt ${attempts}`;
}

export function getEnrichmentStatusDetail(state: EnrichmentState) {
  if (state.status === "failed") {
    return state.error ?? "AI enrichment failed.";
  }

  if (state.status === "ready") {
    return "Generated metadata is ready across the relevant Minakeep surfaces.";
  }

  return "The save succeeded and Minakeep is refreshing this view while the configured Mina endpoint responds.";
}
